previewCss:
.darma-loader-darma-custom-601 {--loader-bg: var(--loader-bg, #ffffff);
  --loader-secondary-color: var(--loader-secondary-color, #fb7185);
   width: 30px;
   height: 30px;
   color: var(--loader-color, #e11d48);
   display: flex;
   background: linear-gradient(currentColor 0 0) center/calc(100% - 30px) 10px, conic-gradient(from -136deg at right,#0000 ,currentColor 1deg 90deg,#0000 91deg) right/15px 100%, conic-gradient(from 44deg at left ,#0000 ,currentColor 1deg 90deg,#0000 91deg) left /15px 100%;
   background-repeat: no-repeat;
   animation: darma-loader-darma-custom-601-l8 .5s infinite alternate;
}
.darma-loader-darma-custom-601:before  {
  content: "";
   flex: 1;
   background: inherit;
   transform: rotate(90deg);
}
@keyframes darma-loader-darma-custom-601-l8  {
  90%,100%{width:80px}
}

